using System.ComponentModel;
using System.Net;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build the chat client (MEAI abstraction over OpenAI) --------------------

IChatClient chatClient = new ChatClientBuilder(
        new OpenAI.OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
    .Build();

// --- Tools -------------------------------------------------------------------

var notepad = new Notepad();

var tools = new AIFunction[]
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
        {
            return WebSearch.SearchAsync(query);
        },
        "web_search",
        "Searches the web for a given query and returns a list of result snippets with titles and URLs."),

    AIFunctionFactory.Create(
        ([Description("The text content to save as a research note")] string note) =>
        {
            notepad.Add(note);
            return $"Note saved. You now have {notepad.Count} note(s).";
        },
        "save_note",
        "Saves a research note for later reference when writing the final summary."),

    AIFunctionFactory.Create(
        () =>
        {
            return notepad.Count == 0
                ? "No notes saved yet."
                : string.Join("\n---\n", notepad.GetAll());
        },
        "read_notes",
        "Reads all previously saved research notes."),
};

// --- Agent -------------------------------------------------------------------

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. When the user gives you a topic:
        1. Use web_search (multiple queries if needed) to find relevant information.
        2. Use save_note to record key findings as you go.
        3. After gathering enough information, use read_notes to review everything.
        4. Produce a well-structured summary with sections and source URLs.
        Keep searches focused. Save concise notes. Cite your sources.
        """,
    name: "ResearchAgent",
    description: "Researches a topic using web search and produces a summary.",
    tools: tools);

// --- Run ---------------------------------------------------------------------

Console.WriteLine("╔══════════════════════════════════════════════╗");
Console.WriteLine("║          🔍  Research Agent  🔍              ║");
Console.WriteLine("╠══════════════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or 'quit' to    ║");
Console.WriteLine("║  exit.                                       ║");
Console.WriteLine("╚══════════════════════════════════════════════╝");
Console.WriteLine();

var session = await agent.CreateSessionAsync();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Topic> ");
    Console.ResetColor();

    var input = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(input)) continue;
    if (input.Equals("quit", StringComparison.OrdinalIgnoreCase)) break;

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("\nResearching...\n");
    Console.ResetColor();

    notepad.Clear();

    var chatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    };

    var runOptions = new ChatClientAgentRunOptions(chatOptions);

    var response = await agent.RunAsync(input, session, options: runOptions);

    Console.ForegroundColor = ConsoleColor.Green;
    Console.WriteLine(response.Text);
    Console.ResetColor();
    Console.WriteLine();
}

// --- Supporting classes ------------------------------------------------------

/// <summary>Simple in-memory notepad for the agent to store research findings.</summary>
sealed class Notepad
{
    private readonly List<string> _notes = [];

    public int Count => _notes.Count;
    public void Add(string note) => _notes.Add(note);
    public void Clear() => _notes.Clear();
    public IReadOnlyList<string> GetAll() => _notes;
}

/// <summary>Web search using the Google Custom Search JSON API, with a
/// built-in fallback that scrapes DuckDuckGo Lite (no key required).</summary>
static class WebSearch
{
    private static readonly HttpClient Http = new();

    public static async Task<string> SearchAsync(string query)
    {
        try
        {
            return await DuckDuckGoSearchAsync(query);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static async Task<string> DuckDuckGoSearchAsync(string query)
    {
        var encoded = WebUtility.UrlEncode(query);
        var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";

        using var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.UserAgent.ParseAdd(
            "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

        using var response = await Http.SendAsync(request);
        response.EnsureSuccessStatusCode();
        var html = await response.Content.ReadAsStringAsync();

        // Extract result snippets from DuckDuckGo Lite HTML
        var results = ParseDuckDuckGoLite(html);
        return results.Count == 0
            ? "No results found."
            : string.Join("\n\n", results.Take(5));
    }

    private static List<string> ParseDuckDuckGoLite(string html)
    {
        var results = new List<string>();
        var links = System.Text.RegularExpressions.Regex.Matches(
            html,
            @"<a[^>]+rel=""nofollow""[^>]+href=""([^""]+)""[^>]*>\s*(.+?)\s*</a>",
            System.Text.RegularExpressions.RegexOptions.Singleline);

        var snippets = System.Text.RegularExpressions.Regex.Matches(
            html,
            @"<td\s+class=""result-snippet""[^>]*>\s*(.+?)\s*</td>",
            System.Text.RegularExpressions.RegexOptions.Singleline);

        for (var i = 0; i < links.Count && i < 8; i++)
        {
            var title = StripHtml(links[i].Groups[2].Value).Trim();
            var href = links[i].Groups[1].Value;
            var snippet = i < snippets.Count
                ? StripHtml(snippets[i].Groups[1].Value).Trim()
                : "";

            if (!string.IsNullOrWhiteSpace(title))
            {
                results.Add($"[{title}]({href})\n{snippet}");
            }
        }

        return results;
    }

    private static string StripHtml(string html) =>
        System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", "");
}

